#define UART_CTRL_REG (*(volatile uint32_t*)(UART_BASE_ADDR + 0x08))
#define UART_BAUD_REG (*(volatile uint32_t*)(UART_BASE_ADDR + 0x0C))

#define GPIO_BASE_ADDR 0x40020000
#define GPIOA_MODER (*(volatile uint32_t*)(GPIO_BASE_ADDR + 0x00))
