void parse_command(char* cmd_line) {
    char* argv[MAX_ARGS];
    int argc = 0;
    char* token;
    
    token = strtok(cmd_line, " \t\r\n");
    while (token != NULL && argc < MAX_ARGS) {
        argv[argc++] = token;
        token = strtok(NULL, " \t\r\n");
    }
    
    if (argc == 0) {
        return;
    }
    
    for (int i = 0; commands[i].name != NULL; i++) {
        if (strcmp(argv[0], commands[i].name) == 0) {
            commands[i].handler(argc, argv);
            return;
        }
    }
    
    sprintf(tx_buffer, "Unknown command: %s\r\n", argv[0]);
    uart_puts(tx_buffer);
    uart_puts("Type 'help' for available commands\r\n");
}

